#include<bits/stdc++.h>
using namespace std;
const int MAXN = 5e5 + 10;
int fa[3 * MAXN];//1~n 是同类 , n + 1 ~2 * n 是食物 ,2 * n + 1 ~ 3*n是天敌 
int find(int x){
	return fa[x] == x ? x : fa[x] = find(fa[x]);
}
int main()
{
	for(int i = 0; i < MAXN; i++)fa[i] = i;
	int n,k;
	cin >> n >> k;
	int cnt = 0;
	while(k--){
		int t, x, y;
		cin >> t >> x >> y;
		if(x > n || y > n){
			cnt++;
			continue;
		}
		if(t == 1){
			//如果x的食物与y是同类或y的食物与x是同类,cnt++
			if(find(x + n) == find(y) || find(x) == find(y + n)){
				cnt++;
//				cout << t << " " << x << " " << y << endl;
			}
			else{
				//将x和y划为同类,y的天敌是x的天敌,y的食物也是x的食物
				fa[find(x)] = find(y);//划为同类 
				fa[find(x + n)] = find(y + n);//食物共享 
				fa[find(x + 2 * n)] = find(y + 2 * n); //天敌共抵 
			}
		}else{
			//如果是同类         或者   （x是y的食物）！！！,cnt++ 要考虑x被y吃的情况 
			if(find(x) == find(y) || find(x) == find(y + n) || x == y){
				cnt++;
//				cout << t << " " << x << " " << y << endl;
			}
			else{
				//把每个并查集里面的x和y化为x吃y
				fa[find(x + n)] =  find(y);//x的食物是y 
				fa[find(x + 2 * n)] =find(y + n);//x的天敌是y的食物 
				fa[find(x)] = find(y + 2 * n);//x是y的天敌 
			}
		}
	}
	cout << cnt;
	return 0;
}
